            };
            IRatingService ratingService = GetRatingService();
            ratingService.SetDefaultGameRatingValues(game);
            return game;
        }

        public static Match CreateTestMatch(ICollection<Player> players, ICollection<Game> games)
        {
            Random rnd = new Random();
            Match match = new Match();
            int gameIndex = rnd.Next(0, games.Count);
            match.Game = games.ElementAt(gameIndex);
            //int matchStateIndex = rnd.Next(0, MatchState.GetAllMatchStates.Count);
            //match.State = MatchState.GetMatchState((MatchStateEnum)matchStateIndex);
            match.State = MatchState.Done;
            match.StartTime = DateTime.Now  + TimeSpan.FromDays(rnd.Next(1, 31)) + TimeSpan.FromMinutes(rnd.Next(1, 60));
            if (match.State == MatchState.Done)
            {
                match.StopTime = DateTime.Now + TimeSpan.FromMinutes(rnd.Next(1, 21));
            }
            match.Score1 = rnd.Next(10 + 1);
            match.Score2 = rnd.Next(10 + 1);

            int player1Index = rnd.Next(0, players.Count);
            int player2Index = rnd.Next(0, players.Count);
            while (player1Index == player2Index)
            {
                player2Index = rnd.Next(0, players.Count);
            }
            int teamSize1 = rnd.Next(1, 3);
            if (teamSize1 == 1)
            {
                match.Team1 = CreateTestTeam(match.Game, players.ElementAt(player1Index));
            }
            else if (teamSize1 == 2)
            {
                match.Team1 = CreateTestTeam(match.Game, players.ElementAt(player1Index), players.ElementAt(player2Index));
            }

            int player3Index = rnd.Next(0, players.Count);
            while (player1Index == player3Index || player2Index == player3Index)
            {
                player3Index = rnd.Next(0, players.Count);
            }
            int player4Index = rnd.Next(0, players.Count);
            while (player1Index == player4Index || player2Index == player4Index || player3Index == player4Index)
            {
                player4Index = rnd.Next(0, players.Count);
            }
            int teamSize2 = rnd.Next(1, 3);
            if (teamSize2 == 1)
            {
                match.Team2 = CreateTestTeam(match.Game, players.ElementAt(player3Index), null, match.Team1.Name);
            }
            else if (teamSize2 == 2)
            {
                match.Team2 = CreateTestTeam(match.Game, players.ElementAt(player3Index), players.ElementAt(player4Index), match.Team1.Name);
            }
            return match;
        }

        public static Team CreateTestTeam(Game game, Player p1, Player p2 = null, string team1Name = null)
        {
            Team team = new Team
            {
                Player1 = p1,
                Player2 = p2
            };
            Random rnd = new Random();
            if (game.Id == GameFifaId)
            {
                int teamIndex = rnd.Next(0, FifaTeams.Length);
                team.Name = FifaTeams[teamIndex];
                while (team.Name == team1Name)
                {
                    teamIndex = rnd.Next(0, FifaTeams.Length);
                    team.Name = FifaTeams[teamIndex];
                }
            }
            else if (game.Id == GameRocketLeague)
            {
                int teamIndex = rnd.Next(0, RocketLeagueTeams.Length);
                team.Name = RocketLeagueTeams[teamIndex];
                while (team.Name == team1Name)
                {
                    teamIndex = rnd.Next(0, RocketLeagueTeams.Length);
                    team.Name = RocketLeagueTeams[teamIndex];
                }
            }
            else
            {
                team.Name = "Team-" + team.Id;
            }
            return team;
        }

